import 'package:flutter/material.dart';import '../services/api_service.dart';
class OrderScreen extends StatefulWidget{final Map<String,dynamic> table;const OrderScreen({super.key,required this.table});@override State<OrderScreen> createState()=>_OrderScreenState();}class _OrderScreenState extends State<OrderScreen>{List<dynamic> products=[];final quantities=<String,int>{};Map<String,dynamic>? tab;bool loading=true;@override void initState(){super.initState();load();}Future<void> load()async{tab=await ApiService.instance.openTable(widget.table['id']);products=await ApiService.instance.products();if(mounted)setState(()=>loading=false);}Future<void> send()async{final items=quantities.entries.where((e)=>e.value>0).map((e)=>{'productId':e.key,'quantity':e.value}).toList();if(items.isEmpty)return;await ApiService.instance.createOrder(tab!['id'],items);if(mounted){ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content:Text('Pedido enviado para a cozinha')));setState(()=>quantities.clear());}}Future<void> close()async{await ApiService.instance.closeTable(widget.table['id']);if(mounted)Navigator.pop(context);}@override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:Text('Mesa ${widget.table['number']}'),actions:[TextButton.icon(onPressed:close,icon:const Icon(Icons.receipt_long),label:const Text('Fechar'))]),body:loading?const Center(child:CircularProgressIndicator()):ListView.builder(padding:const EdgeInsets.fromLTRB(16,16,16,100),itemCount:products.length,itemBuilder:(_,i){final p=products[i];final qty=quantities[p['id']]??0;return Card(child:ListTile(title:Text(p['name']),subtitle:Text('R\$ ${p['price']} · ${p['category']['name']}'),trailing:Row(mainAxisSize:MainAxisSize.min,children:[IconButton(onPressed:qty==0?null:()=>setState(()=>quantities[p['id']]=qty-1),icon:const Icon(Icons.remove)),Text('$qty'),IconButton(onPressed:()=>setState(()=>quantities[p['id']]=qty+1),icon:const Icon(Icons.add))])));}),floatingActionButton:FloatingActionButton.extended(onPressed:send,icon:const Icon(Icons.send),label:const Text('Enviar cozinha')));}
